/**
 * Bundled copy of .github/workflows/pr-visual-recap.yml so the CLI can write the
 * PR Visual Recap workflow into a user repo via
 * `agent-native skills add visual-plan --with-github-action`.
 *
 * AUTO-GENERATED — keep byte-identical with the source workflow. A sync test in
 * recap.spec.ts fails if these drift. Regenerate from the YAML with the snippet
 * in recap.spec.ts.
 */

export const PR_VISUAL_RECAP_WORKFLOW_YML =
  "name: PR Visual Recap\n\n# Turns every PR into a \"visual code review\" — a reverse plan — by letting a real\n# coding agent RUN THE REPO'S visual-recap SKILL against the diff. The agent\n# (Claude Code by default, or Codex) reads the skill, reasons over the change,\n# publishes an Agent-Native Plan via the plan MCP tools, and writes the plan URL\n# to recap-url.txt. The workflow then screenshots that plan in headless Chrome,\n# uploads the PNG to the plan app's signed public image route, and upserts ONE\n# sticky PR comment with the inline screenshot + the interactive link.\n#\n# Design notes:\n#  - Plain `pull_request` (NOT `pull_request_target`) so fork code can never see\n#    the publish/agent secrets. Fork PRs are a silent no-op.\n#  - The `gate` job is a cheap switch: drafts, forks, bot authors, and the\n#    missing-secret case short-circuit with NO comment and NO compute. Merging\n#    this workflow before the secrets exist is a safe no-op.\n#  - The recap is INFORMATIONAL ONLY. It is not a required check and failures\n#    surface as an explanatory sticky comment, never a red X on unrelated code.\n#  - Backend is selectable with the `VISUAL_RECAP_AGENT` repo variable\n#    (claude | codex; default claude). Model and reasoning depth are tunable with\n#    `VISUAL_RECAP_MODEL` (e.g. gpt-5.5) and `VISUAL_RECAP_REASONING`\n#    (none|minimal|low|medium|high|xhigh; Codex only). The CLI invocation is\n#    auto-detected: local source inside this monorepo, the published\n#    @agent-native/core elsewhere — no repo variable needed.\n#  - Only two secrets are required: PLAN_RECAP_TOKEN (publish) and the chosen\n#    backend's API key. PLAN_RECAP_APP_URL defaults to the hosted plan app.\n#  - Nothing here is deterministic: the skill's instructions drive the recap.\n\non:\n  # Run on PRs into any base branch — the generated workflow ships to repos whose\n  # default branch may not be `main`. The gate job below still no-ops drafts,\n  # forks, bots, and the missing-secret case, so this stays cheap.\n  pull_request:\n    types: [opened, synchronize, reopened, ready_for_review]\n\n# Least privilege by default: the workflow gets read-only `contents` and each\n# job escalates only what it needs (gate reads PR files; recap writes the sticky\n# comment). Avoids a broad write token sitting on the job that runs the agent.\npermissions:\n  contents: read\n\nconcurrency:\n  group: pr-visual-recap-${{ github.event.pull_request.number }}\n  cancel-in-progress: true\n\nenv:\n  VISUAL_RECAP_AGENT: ${{ vars.VISUAL_RECAP_AGENT || 'claude' }}\n\njobs:\n  # --------------------------------------------------------------------------\n  # Cheap gate: decide whether to do any work at all. Sets run=false (silent\n  # no-op) for drafts, forks, bot authors, the missing-secret case, an invalid\n  # agent/model, or a PR that touches recap-control files. The decision logic\n  # is the security boundary and lives in the versioned `recap gate` CLI\n  # subcommand (packages/core/src/cli/recap.ts) — not inline here — so it ships\n  # with the pinned package and is unit-tested. This job runs NO PR-checked-out\n  # code: the consumer path is plain `npx @agent-native/core@<pinned>`, and the\n  # framework dogfood path runs the repo's own tsx source.\n  # --------------------------------------------------------------------------\n  gate:\n    name: Gate\n    runs-on: ubuntu-latest\n    timeout-minutes: 10\n    # Only needs to read PR file metadata for the self-modifying guard.\n    permissions:\n      contents: read\n      pull-requests: read\n    outputs:\n      run: ${{ steps.decide.outputs.run }}\n      agent: ${{ steps.decide.outputs.agent }}\n    steps:\n      # Check out first so the resolve step below can probe for local source.\n      # Cheap (contents: read) and lets the framework dogfood its own CLI; a\n      # consumer repo's checkout simply won't contain packages/core, so the probe\n      # falls back to the pinned published package. Hardening: don't persist the\n      # token in .git/config — the gate talks to GitHub via GH_TOKEN, never push.\n      - uses: actions/checkout@df4cb1c069e1874edd31b4311f1884172cec0e10 # v6.0.3\n        with:\n          persist-credentials: false\n\n      # Resolve the CLI invocation the SAME way the recap job does: dogfood local\n      # source inside this monorepo, otherwise the pinned published package. The\n      # pnpm setup/install steps below run ONLY for the local-source path, so the\n      # generated workflow works out-of-box in npm/yarn consumer repos (which have\n      # no pnpm-lock.yaml) by falling back to `npx @agent-native/core@<pinned>`,\n      # which needs node alone.\n      - name: Resolve recap CLI\n        id: cli\n        run: |\n          if [ -f packages/core/src/cli/index.ts ]; then\n            echo \"RECAP_CLI=pnpm exec tsx packages/core/src/cli/index.ts\" >> \"$GITHUB_ENV\"\n            echo \"local=true\" >> \"$GITHUB_OUTPUT\"\n          else\n            echo \"RECAP_CLI=npx -y @agent-native/core@0.45.0\" >> \"$GITHUB_ENV\"\n            echo \"local=false\" >> \"$GITHUB_OUTPUT\"\n          fi\n\n      - uses: pnpm/action-setup@0e279bb959325dab635dd2c09392533439d90093 # v6.0.8\n        if: steps.cli.outputs.local == 'true'\n\n      - uses: actions/setup-node@48b55a011bda9f5d6aeb4c2d9c7362e8dae4041e # v6.4.0\n        with:\n          node-version: \"22\"\n          cache: ${{ steps.cli.outputs.local == 'true' && 'pnpm' || '' }}\n\n      - name: Install workspace (local source only)\n        if: steps.cli.outputs.local == 'true'\n        run: pnpm install --frozen-lockfile --ignore-scripts\n\n      # The gate decision. Reads the pull_request payload from $GITHUB_EVENT_PATH,\n      # the secret-presence/agent/model signals from the env below, the repo from\n      # $GITHUB_REPOSITORY, and the PR's changed files from the GitHub REST API\n      # (paged, with GH_TOKEN). Writes run + the normalized agent to $GITHUB_OUTPUT\n      # and fails CLOSED (run=false) on any file-list error.\n      - name: Decide\n        id: decide\n        env:\n          # Presence-only signals — we never expose the secret VALUES to the gate.\n          # PLAN_RECAP_APP_URL defaults to the hosted app, so only the token is required.\n          HAS_PLAN: ${{ secrets.PLAN_RECAP_TOKEN != '' }}\n          HAS_ANTHROPIC: ${{ secrets.ANTHROPIC_API_KEY != '' }}\n          HAS_OPENAI: ${{ secrets.OPENAI_API_KEY != '' }}\n          AGENT: ${{ env.VISUAL_RECAP_AGENT }}\n          VISUAL_RECAP_MODEL: ${{ vars.VISUAL_RECAP_MODEL }}\n          GH_TOKEN: ${{ github.token }}\n        run: |\n          set -euo pipefail\n          $RECAP_CLI recap gate\n\n  # --------------------------------------------------------------------------\n  # Recap: collect the diff, let the agent run the skill + publish, screenshot\n  # the result, and upsert the sticky comment.\n  # --------------------------------------------------------------------------\n  recap:\n    name: Generate visual recap\n    needs: gate\n    if: needs.gate.outputs.run == 'true'\n    runs-on: ubuntu-latest\n    # The agent run + headless-Chrome screenshot dominate; cap so a hung agent\n    # or browser can't burn a full 6h runner.\n    timeout-minutes: 30\n    # Escalate only here: write the sticky PR comment (issues+pull-requests),\n    # create/update the informational Visual Recap check (checks), and read the\n    # checked-out source (contents). The agent step that runs untrusted PR diff\n    # content gets no more than this.\n    permissions:\n      checks: write\n      contents: read\n      issues: write\n      pull-requests: write\n    env:\n      PLAN_RECAP_APP_URL: ${{ secrets.PLAN_RECAP_APP_URL || 'https://plan.agent-native.com' }}\n      PLAN_RECAP_TOKEN: ${{ secrets.PLAN_RECAP_TOKEN }}\n      GH_TOKEN: ${{ github.token }}\n      PR_NUMBER: ${{ github.event.pull_request.number }}\n      HEAD_SHA: ${{ github.event.pull_request.head.sha }}\n      VISUAL_RECAP_MODEL: ${{ vars.VISUAL_RECAP_MODEL }}\n      VISUAL_RECAP_REASONING: ${{ vars.VISUAL_RECAP_REASONING }}\n    steps:\n      - name: Start visual recap check\n        id: recap_check\n        continue-on-error: true\n        uses: actions/github-script@3a2844b7e9c422d3c10d287c895573f7108da1b3 # v9.0.0\n        with:\n          script: |\n            const workflowUrl = `${process.env.GITHUB_SERVER_URL}/${process.env.GITHUB_REPOSITORY}/actions/runs/${process.env.GITHUB_RUN_ID}`;\n\n            try {\n              const response = await github.rest.checks.create({\n                owner: context.repo.owner,\n                repo: context.repo.repo,\n                name: 'Visual Recap',\n                head_sha: process.env.HEAD_SHA,\n                status: 'in_progress',\n                started_at: new Date().toISOString(),\n                details_url: workflowUrl,\n                output: {\n                  title: 'Review in progress',\n                  summary: 'Generating a visual code-review recap for this pull request.',\n                },\n              });\n              core.setOutput('check_run_id', String(response.data.id));\n            } catch (error) {\n              core.warning(`Could not create Visual Recap check run: ${error.message}`);\n              core.setOutput('check_run_id', '');\n            }\n\n      - uses: actions/checkout@df4cb1c069e1874edd31b4311f1884172cec0e10 # v6.0.3\n        with:\n          fetch-depth: 0\n          # Don't leave the job's GITHUB_TOKEN in .git/config — this job runs an\n          # agent over untrusted PR diff content, and it talks to GitHub via the\n          # GH_TOKEN env for gh API calls, never via git push. Hardening only.\n          persist-credentials: false\n\n      # Resolve the CLI invocation once: dogfood local source inside this\n      # monorepo, otherwise the published package. No repo variable needed. The\n      # pnpm setup/install steps below run ONLY for the local-source path, so the\n      # generated workflow works out-of-box in npm/yarn consumer repos (which\n      # have no pnpm-lock.yaml) by falling back to `npx @agent-native/core`.\n      - name: Resolve recap CLI\n        id: cli\n        run: |\n          if [ -f packages/core/src/cli/index.ts ]; then\n            echo \"RECAP_CLI=pnpm exec tsx packages/core/src/cli/index.ts\" >> \"$GITHUB_ENV\"\n            echo \"local=true\" >> \"$GITHUB_OUTPUT\"\n          else\n            echo \"RECAP_CLI=npx -y @agent-native/core@0.45.0\" >> \"$GITHUB_ENV\"\n            echo \"local=false\" >> \"$GITHUB_OUTPUT\"\n          fi\n\n      - uses: pnpm/action-setup@0e279bb959325dab635dd2c09392533439d90093 # v6.0.8\n        if: steps.cli.outputs.local == 'true'\n\n      - uses: actions/setup-node@48b55a011bda9f5d6aeb4c2d9c7362e8dae4041e # v6.4.0\n        with:\n          node-version: \"22\"\n          cache: ${{ steps.cli.outputs.local == 'true' && 'pnpm' || '' }}\n\n      - name: Install workspace (local source only)\n        if: steps.cli.outputs.local == 'true'\n        run: pnpm install --frozen-lockfile --ignore-scripts\n\n      # Collect a BOUNDED diff between the PR base and head. The CLI excludes\n      # lockfiles, build output, and snapshots (noise), caps the byte size at\n      # ~600KB (over the cap it truncates recap.diff at a line boundary and sets\n      # `huge=true` so the agent is told to summarize), and classifies `tiny`.\n      # The CLI writes the bytes/changed/huge/tiny outputs to $GITHUB_OUTPUT\n      # itself — see `recap collect-diff` in packages/core/src/cli/recap.ts.\n      - name: Collect bounded diff\n        id: diff\n        env:\n          BASE_SHA: ${{ github.event.pull_request.base.sha }}\n        run: |\n          set -euo pipefail\n          $RECAP_CLI recap collect-diff --base \"$BASE_SHA\" --head \"$HEAD_SHA\" --out recap.diff --stat recap.stat\n\n      # Secret pre-scan: refuse to hand a diff that looks like it leaks\n      # credentials to the agent. Prints { suppressed, reason } and always exits 0.\n      - name: Secret scan\n        id: scan\n        if: steps.diff.outputs.tiny != 'true'\n        run: |\n          set -uo pipefail\n          # Fail CLOSED: if the scanner errors or emits invalid JSON, treat the\n          # diff as suppressed, so a scan failure can never hand a possibly\n          # credential-bearing diff to the agent / plan service.\n          if ! SCAN_JSON=\"$($RECAP_CLI recap scan --diff recap.diff)\"; then\n            SCAN_JSON='{\"suppressed\":true,\"reason\":\"secret scan failed to run; failing closed\"}'\n          fi\n          # Multi-line-safe write: SCAN_JSON could contain newlines, which would\n          # otherwise corrupt $GITHUB_OUTPUT or inject extra keys.\n          {\n            echo 'json<<__RECAP_SCAN_EOF__'\n            echo \"$SCAN_JSON\"\n            echo '__RECAP_SCAN_EOF__'\n          } >> \"$GITHUB_OUTPUT\"\n          SUPPRESSED=$(node -e 'try{process.stdout.write(JSON.parse(process.argv[1]).suppressed?\"true\":\"false\")}catch{process.stdout.write(\"true\")}' \"$SCAN_JSON\")\n          echo \"suppressed=$SUPPRESSED\" >> \"$GITHUB_OUTPUT\"\n\n      # Find the planId from the previous sticky comment so a re-push REPLACES the\n      # same hosted plan (synchronize updates in place, no orphaned plans).\n      - name: Read previous plan id\n        id: prev\n        continue-on-error: true\n        run: |\n          set -euo pipefail\n          PLAN_ID=\"$($RECAP_CLI recap comment find-plan-id --repo \"$GITHUB_REPOSITORY\" --issue \"$PR_NUMBER\" --token \"$GH_TOKEN\")\"\n          echo \"plan_id=$PLAN_ID\" >> \"$GITHUB_OUTPUT\"\n\n      # Build the agent prompt = the repo's visual-recap SKILL.md + a task wrapper.\n      - name: Build recap prompt\n        id: prompt\n        if: steps.diff.outputs.tiny != 'true' && steps.scan.outputs.suppressed != 'true'\n        env:\n          # Pass step outputs through env, NOT via ${{ }} interpolation into the\n          # run body: the plan id is parsed from a PR sticky comment, so a crafted\n          # value interpolated into the script text could break quoting and run\n          # arbitrary shell on the runner that holds the publish/API secrets.\n          # As env vars they are inert data; args are assembled in a bash array\n          # so each is passed as a single quoted token.\n          PREV_PLAN_ID: ${{ steps.prev.outputs.plan_id }}\n          DIFF_HUGE: ${{ steps.diff.outputs.huge }}\n        run: |\n          set -euo pipefail\n          ARGS=(--diff recap.diff --stat recap.stat --pr \"$PR_NUMBER\" --repo \"$GITHUB_REPOSITORY\" --head \"$HEAD_SHA\" --app-url \"$PLAN_RECAP_APP_URL\" --out recap-prompt.md)\n          if [ \"${DIFF_HUGE:-}\" = \"true\" ]; then ARGS+=(--huge); fi\n          if [ -n \"${PREV_PLAN_ID:-}\" ]; then ARGS+=(--prev-plan-id \"$PREV_PLAN_ID\"); fi\n          $RECAP_CLI recap build-prompt \"${ARGS[@]}\"\n\n      # Wire the plan MCP server for the chosen backend, then run the agent. The\n      # agent follows the skill, calls create-visual-recap + set-resource-visibility,\n      # and writes the published plan URL to recap-url.txt. continue-on-error so a\n      # failed agent run becomes an explanatory comment, not a red X.\n      - name: Run agent (Claude Code)\n        id: claude\n        if: needs.gate.outputs.agent == 'claude' && steps.diff.outputs.tiny != 'true' && steps.scan.outputs.suppressed != 'true'\n        continue-on-error: true\n        env:\n          ANTHROPIC_API_KEY: ${{ secrets.ANTHROPIC_API_KEY }}\n        run: |\n          set -uo pipefail\n          MCP_CONFIG=\"$RUNNER_TEMP/plan-mcp.json\"\n          # Write the plan MCP config (reads PLAN_RECAP_TOKEN from env) — see\n          # `recap mcp-config` in packages/core/src/cli/recap.ts.\n          $RECAP_CLI recap mcp-config --agent claude --app-url \"$PLAN_RECAP_APP_URL\" --out \"$MCP_CONFIG\"\n          # VISUAL_RECAP_MODEL picks the Claude model; reasoning depth is model-driven\n          # for Claude Code, so VISUAL_RECAP_REASONING only applies to the Codex backend.\n          CLAUDE_ARGS=(-p \"$(cat recap-prompt.md)\" --mcp-config \"$MCP_CONFIG\" --allowedTools \"Read,Write,Bash(git diff:*),mcp__plan__create-visual-recap,mcp__plan__set-resource-visibility\" --permission-mode dontAsk --output-format json)\n          if [ -n \"${VISUAL_RECAP_MODEL:-}\" ]; then CLAUDE_ARGS+=(--model \"$VISUAL_RECAP_MODEL\"); fi\n          # Capture the final JSON result (usage + total_cost_usd) for the usage step.\n          npx -y @anthropic-ai/claude-code@2 \"${CLAUDE_ARGS[@]}\" > claude-result.json || true\n          rm -f \"$MCP_CONFIG\" || true\n\n      - name: Run agent (Codex)\n        id: codex\n        if: needs.gate.outputs.agent == 'codex' && steps.diff.outputs.tiny != 'true' && steps.scan.outputs.suppressed != 'true'\n        continue-on-error: true\n        env:\n          OPENAI_API_KEY: ${{ secrets.OPENAI_API_KEY }}\n        run: |\n          set -uo pipefail\n          # Write ~/.codex/config.toml with the plan MCP server. The CLI\n          # JSON.stringifies the URL value so a stray quote/newline in\n          # PLAN_RECAP_APP_URL can't break out of the TOML string, and creates\n          # the ~/.codex dir — see `recap mcp-config` in\n          # packages/core/src/cli/recap.ts.\n          $RECAP_CLI recap mcp-config --agent codex --app-url \"$PLAN_RECAP_APP_URL\"\n          # Authenticate with the API key explicitly. Relying on the bare\n          # OPENAI_API_KEY env var alone is unreliable on the gpt-5.5 WebSocket\n          # transport: the Authorization header is dropped on the wss path and\n          # its HTTPS fallback, surfacing as `401 Missing bearer or basic\n          # authentication in header` (openai/codex#15492). `codex login\n          # --with-api-key` reads the key from stdin and writes ~/.codex/auth.json,\n          # which the exec path reads reliably; piping via stdin keeps the key out\n          # of the process args. Non-fatal so a login hiccup still yields the\n          # explanatory recap comment rather than a red X.\n          printenv OPENAI_API_KEY | npx -y @openai/codex@0 login --with-api-key || true\n          # VISUAL_RECAP_MODEL (e.g. gpt-5.5) and VISUAL_RECAP_REASONING\n          # (none|minimal|low|medium|high|xhigh) tune the Codex run.\n          #\n          # The GitHub runner is itself an ephemeral, throwaway sandbox, so run\n          # Codex with sandboxing and approvals disabled. Codex's own bubblewrap\n          # sandbox cannot initialize on the runner (\"could not find bubblewrap\n          # on PATH\"), which makes every shell command fail at startup so the\n          # agent cannot even read recap.diff; and under an approval gate the\n          # write-side plan MCP call (create-visual-recap) is auto-cancelled\n          # (\"user cancelled MCP tool call\"). --dangerously-bypass-approvals-and-sandbox\n          # is the documented invocation for externally-sandboxed CI and clears both.\n          CODEX_ARGS=(exec --dangerously-bypass-approvals-and-sandbox --skip-git-repo-check)\n          if [ -n \"${VISUAL_RECAP_MODEL:-}\" ]; then CODEX_ARGS+=(--model \"$VISUAL_RECAP_MODEL\"); fi\n          # Validate reasoning against the known enum before embedding it in the\n          # codex `-c` TOML override, so an unexpected value can't alter the config.\n          case \"${VISUAL_RECAP_REASONING:-}\" in\n            none|minimal|low|medium|high|xhigh)\n              CODEX_ARGS+=(-c \"model_reasoning_effort=\\\"$VISUAL_RECAP_REASONING\\\"\") ;;\n            \"\") ;;\n            *) echo \"Ignoring invalid VISUAL_RECAP_REASONING: $VISUAL_RECAP_REASONING\" ;;\n          esac\n          npx -y @openai/codex@0 \"${CODEX_ARGS[@]}\" --json \"$(cat recap-prompt.md)\" | tee codex-events.jsonl || true\n\n      # The agent's only hand-off: recap-url.txt with the published plan URL.\n      - name: Read plan URL\n        id: url\n        if: steps.diff.outputs.tiny != 'true' && steps.scan.outputs.suppressed != 'true'\n        run: |\n          set -uo pipefail\n          PLAN_URL=\"\"\n          if [ -f recap-url.txt ]; then PLAN_URL=\"$(tr -d '\\r\\n' < recap-url.txt | tr -d ' ')\"; fi\n          echo \"plan_url=$PLAN_URL\" >> \"$GITHUB_OUTPUT\"\n          if [ -n \"$PLAN_URL\" ]; then echo \"ok=true\" >> \"$GITHUB_OUTPUT\"; else echo \"ok=false\" >> \"$GITHUB_OUTPUT\"; fi\n\n      # Capture the agent run token usage and attach it to the published recap\n      # so the recap row carries input/output/cached tokens, the model, and a\n      # cost estimate. Informational and best-effort: never fails the job.\n      - name: Attach usage\n        if: steps.url.outputs.ok == 'true'\n        continue-on-error: true\n        env:\n          PLAN_URL: ${{ steps.url.outputs.plan_url }}\n          # Use the gate-NORMALIZED agent (lowercased + validated), not the raw\n          # VISUAL_RECAP_AGENT repo var, so a value like \"Codex\" still selects the\n          # codex result file and labels usage on the right backend.\n          RECAP_AGENT: ${{ needs.gate.outputs.agent }}\n        run: |\n          set -uo pipefail\n          RESULT=claude-result.json\n          if [ \"$RECAP_AGENT\" = \"codex\" ]; then RESULT=codex-events.jsonl; fi\n          if [ -f \"$RESULT\" ]; then $RECAP_CLI recap usage --plan-url \"$PLAN_URL\" --agent \"$RECAP_AGENT\" --result-file \"$RESULT\" --model \"${VISUAL_RECAP_MODEL:-}\" --app-url \"$PLAN_RECAP_APP_URL\" --token \"$PLAN_RECAP_TOKEN\" || true; fi\n\n      # Screenshot the published plan in headless Chrome and upload the PNG to the\n      # plan app's signed public image route. Best-effort: never fails the job.\n      - name: Screenshot + upload\n        id: shot\n        if: steps.url.outputs.ok == 'true'\n        continue-on-error: true\n        env:\n          # Pass the agent-produced plan URL through the environment, never via\n          # ${{ }} interpolation into the run script: recap-url.txt is untrusted\n          # agent output, so inlining it would be a shell-injection vector.\n          PLAN_URL: ${{ steps.url.outputs.plan_url }}\n        run: |\n          set -uo pipefail\n          pnpm exec playwright install --with-deps chromium 2>/dev/null || npx -y playwright@1 install --with-deps chromium || true\n          SHOT_JSON=\"$($RECAP_CLI recap shot --url \"$PLAN_URL\" --token \"$PLAN_RECAP_TOKEN\" --app-url \"$PLAN_RECAP_APP_URL\" --out recap.png || echo '{}')\"\n          IMAGE_URL=$(node -e 'try{process.stdout.write(JSON.parse(process.argv[1]).imageUrl||\"\")}catch{process.stdout.write(\"\")}' \"$SHOT_JSON\")\n          echo \"image_url=$IMAGE_URL\" >> \"$GITHUB_OUTPUT\"\n          if [ -f recap.png ]; then echo \"captured=true\" >> \"$GITHUB_OUTPUT\"; else echo \"captured=false\" >> \"$GITHUB_OUTPUT\"; fi\n\n      - name: Upload recap screenshot artifact\n        if: steps.shot.outputs.captured == 'true'\n        uses: actions/upload-artifact@043fb46d1a93c77aae656e7c1c64a875d1fc6a0a # v7.0.1\n        with:\n          name: pr-visual-recap-${{ github.event.pull_request.number }}\n          path: recap.png\n          if-no-files-found: ignore\n          retention-days: 14\n\n      # Upsert the single sticky comment: inline screenshot + link on success,\n      # suppressed / failed / tiny variants otherwise. Runs even on a tiny diff\n      # so a prior recap comment is refreshed (not left pointing at a stale SHA).\n      - name: Upsert sticky comment\n        if: always()\n        # The recap is informational/non-blocking: a failed comment upsert must\n        # not turn the whole job red (the agent + screenshot steps are already\n        # continue-on-error).\n        continue-on-error: true\n        env:\n          PLAN_URL: ${{ steps.url.outputs.plan_url }}\n          RECAP_IMAGE_URL: ${{ steps.shot.outputs.image_url }}\n          SUPPRESSED: ${{ steps.scan.outputs.suppressed }}\n          SUPPRESSED_JSON: ${{ steps.scan.outputs.json }}\n          DIFF_HUGE: ${{ steps.diff.outputs.huge }}\n          DIFF_TINY: ${{ steps.diff.outputs.tiny }}\n        run: |\n          set -euo pipefail\n          ARGS=(recap comment upsert --repo \"$GITHUB_REPOSITORY\" --issue \"$PR_NUMBER\" --token \"$GH_TOKEN\")\n          # On a tiny diff, only REFRESH an existing recap comment — never create\n          # a new one — so we add no noise but also can't leave a stale prior\n          # recap behind.\n          if [ \"${DIFF_TINY:-}\" = \"true\" ]; then ARGS+=(--update-only); fi\n          $RECAP_CLI \"${ARGS[@]}\"\n\n      - name: Complete visual recap check\n        if: always() && steps.recap_check.outputs.check_run_id != ''\n        continue-on-error: true\n        uses: actions/github-script@3a2844b7e9c422d3c10d287c895573f7108da1b3 # v9.0.0\n        env:\n          CHECK_RUN_ID: ${{ steps.recap_check.outputs.check_run_id }}\n          PLAN_OK: ${{ steps.url.outputs.ok }}\n          PLAN_URL: ${{ steps.url.outputs.plan_url }}\n          SUPPRESSED: ${{ steps.scan.outputs.suppressed }}\n          SUPPRESSED_JSON: ${{ steps.scan.outputs.json }}\n          DIFF_HUGE: ${{ steps.diff.outputs.huge }}\n          DIFF_TINY: ${{ steps.diff.outputs.tiny }}\n        with:\n          script: |\n            const workflowUrl = `${process.env.GITHUB_SERVER_URL}/${process.env.GITHUB_REPOSITORY}/actions/runs/${process.env.GITHUB_RUN_ID}`;\n            const checkRunId = Number(process.env.CHECK_RUN_ID || 0);\n\n            function canonicalRecapUrl(rawUrl, appUrl) {\n              try {\n                const parsed = new URL(rawUrl);\n                const trusted = new URL(appUrl || 'https://plan.agent-native.com');\n                if (parsed.origin !== trusted.origin) return '';\n\n                const match = parsed.pathname.match(/^\\/(?:plans|recaps)\\/([A-Za-z0-9_-]+)$/);\n                return match ? `${trusted.origin}/recaps/${match[1]}` : '';\n              } catch {\n                return '';\n              }\n            }\n\n            let conclusion = 'neutral';\n            let title = 'Visual recap not generated';\n            let summary = 'The visual recap did not produce a plan URL. This is informational only and does not block the PR.';\n            let text = '';\n            let detailsUrl = workflowUrl;\n\n            if (process.env.PLAN_OK === 'true') {\n              const recapUrl = canonicalRecapUrl(process.env.PLAN_URL || '', process.env.PLAN_RECAP_APP_URL || '');\n              if (recapUrl) {\n                conclusion = 'success';\n                title = 'Visual recap ready';\n                summary = process.env.DIFF_HUGE === 'true'\n                  ? 'A summarized visual recap was generated for this large PR.'\n                  : 'A visual code-review recap was generated for this PR.';\n                detailsUrl = recapUrl;\n                text = `**[Open visual recap](${recapUrl})**`;\n              }\n            } else if (process.env.DIFF_TINY === 'true') {\n              conclusion = 'skipped';\n              title = 'Visual recap skipped';\n              summary = 'The diff is too small to need a visual recap.';\n            } else if (process.env.SUPPRESSED === 'true') {\n              let reason = 'potential secret in diff';\n              try {\n                const parsed = JSON.parse(process.env.SUPPRESSED_JSON || '{}');\n                if (parsed && typeof parsed.reason === 'string') reason = parsed.reason;\n              } catch {\n                // Keep the default reason.\n              }\n              title = 'Visual recap suppressed';\n              summary = `No recap was published because ${reason}.`;\n            }\n\n            try {\n              await github.rest.checks.update({\n                owner: context.repo.owner,\n                repo: context.repo.repo,\n                check_run_id: checkRunId,\n                status: 'completed',\n                conclusion,\n                completed_at: new Date().toISOString(),\n                details_url: detailsUrl,\n                output: { title, summary, text },\n              });\n            } catch (error) {\n              core.warning(`Could not update Visual Recap check run: ${error.message}`);\n            }\n";
